                                                        title="Edit User"
                                                    >
                                                        📝
                                                    </button>
                                                    <button 
                                                        className={`inline-flex items-center p-2 border border-transparent rounded-lg text-red-600 ${isDarkMode ? 'hover:bg-red-900/30' : 'hover:bg-red-100'} transition-colors duration-200`}
