                                                        >
                                                            <span className="mr-2">📝</span>
                                                            Edit User
                                                        </button>
                                                        <button className={`flex items-center w-full px-4 py-2 text-sm ${isDarkMode ? 'text-gray-300 hover:bg-gray-700' : 'text-gray-700 hover:bg-gray-100'} transition-colors duration-200`}>
                                                            <span className="mr-2">📧</span>
                                                            Send Message
                                                        </button>
                                                        <button className={`flex items-center w-full px-4 py-2 text-sm ${isDarkMode ? 'text-gray-300 hover:bg-gray-700' : 'text-gray-700 hover:bg-gray-100'} transition-colors duration-200`}>
